interface.definition:
a!localVariables(
  local!socialScore: 42,
  local!selectedService,
  local!initialRequest: #"urn:appian:record-type:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a"(
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/bd55e7e8-03c6-4f77-988b-8b8f254043d2": false,
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3ae6d220-0450-4065-b61f-4b136d605959": loggedInUser(),
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/f51c6f76-9293-444e-91b7-3287f0bd53b9": now(),
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/df425fdb-0f35-4150-a497-dbf371bc0c0f": #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068411"
  ),
  local!selectedMonth: month(a!defaultValue(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/1248a4bf-108e-4870-8db8-2816b7cd4bea"], today())),
  local!selectedDay: day(a!defaultValue(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/1248a4bf-108e-4870-8db8-2816b7cd4bea"], today())),
  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_cardLayout"(
      contents: {
        #"SYSTEM_SYSRULES_sideBySideLayout"(
          items: {
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextItem_v1"(
                    text: "SERVICE",
                    size: "LARGE"
                  )
                },
                align: "RIGHT"
              )
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "shopping-cart",
                    color: "",
                    size: "EXTRA_LARGE"
                  )
                },
                align: "RIGHT"
              ),
              width: "MINIMIZE"
            )
          },
          alignVertical: "MIDDLE"
        )
      },
      style: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[2],
      showBorder: false
    ),
    contents: {
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_sectionLayout_v1"(
            label: "Rückfrage zu deinem Besuch",
            labelIcon: "calendar",
            labelSize: "LARGE",
            contents: {
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextItem_v1"(
                    text: "Zu deinem Antrag gibt es eine Rückfrage. Du hast 2 Tage Zeit diese zu beantworten. Du kannst deinen Antrag nochmal verändern.",
                    size: "MEDIUM"
                  )
                }
              ),
              #"SYSTEM_SYSRULES_cardLayout"(
                contents: {
                  #"SYSTEM_SYSRULES_sideBySideLayout"(
                    items: {
                      #"SYSTEM_SYSRULES_sideBySideItem"(
                        item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                          labelPosition: "COLLAPSED",
                          value: #"SYSTEM_SYSRULES_richTextIcon"(
                            icon: "question",
                            size: "LARGE_PLUS"
                          )
                        ),
                        width: "MINIMIZE"
                      ),
                      #"SYSTEM_SYSRULES_sideBySideItem"(
                        item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                          labelPosition: "COLLAPSED",
                          value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                            text: ri!question,
                            size: "MEDIUM_PLUS"
                          )
                        )
                      )
                    }
                  ),
                  #"SYSTEM_SYSRULES_horizontalLine"(),
                  #"SYSTEM_SYSRULES_paragraphField"(
                    label: "Deine Antwort",
                    value: ri!answer,
                    saveInto: ri!answer,
                    characterLimit: 4000,
                    required: true
                  )
                },
                style: "WARN",
                shape: "ROUNDED",
                marginBelow: "STANDARD",
                showBorder: false
              ),
              #"SYSTEM_SYSRULES_cardChoiceField"(
                labelPosition: "COLLAPSED",
                data: {
                  {guest: "Oma Gertrud", label: "Oma Gertrud", icon: "user-alt"},
                  {guest: "Ehefrau Sabine", label: "Ehefrau Sabine", icon: "user"},
                  {guest: "Bruder Mickey", label: "Bruder Mickey", icon: "user-secret"},
                  {guest: "Tochter Hanna", label: "Tochter Hanna", icon: "child"},
                  {guest: "Sohn Detlef", label: "Sohn Detlef", icon: "baby"}
                },
                cardTemplate: #"SYSTEM_SYSRULES_cardTemplateBarTextStacked"(
                  id: fv!data.guest,
                  primaryText: fv!data.label,
                  icon: fv!data.icon
                ),
                value: if(
                  a!isNullOrEmpty(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"]),
                  null,
                  split(ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"], ";")
                ),
                saveInto: a!save(
                  target: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"],
                  value: joinarray(save!value, ";")
                ),
                maxSelections: 3,
                required: true
              ),
              #"SYSTEM_SYSRULES_ButtonArrayLayout"(
                buttons: #"SYSTEM_SYSRULES_forEach"(
                  items: enumerate(12),
                  expression: #"SYSTEM_SYSRULES_buttonWidget_v1"(
                    label: text(date(year(today()), fv!index, 1), "mmmm"),
                    value: fv!index,
                    saveInto: {
                      local!selectedMonth
                    },
                    style: if(
                      or(
                        a!isNullOrEmpty(local!selectedMonth),
                        local!selectedMonth = fv!index
                      ),
                      "SOLID",
                      "GHOST"
                    )
                  )
                )
              ),
              #"SYSTEM_SYSRULES_ButtonArrayLayout"(
                buttons: #"SYSTEM_SYSRULES_forEach"(
                  items: enumerate(day(eomonth(date(year(today()), local!selectedMonth, 1), 0))),
                  expression: #"SYSTEM_SYSRULES_buttonWidget_v1"(
                    label: text(date(year(today()), local!selectedMonth, fv!index), "d"),
                    value: fv!index,
                    saveInto: {
                      local!selectedDay
                    },
                    style: if(
                      or(
                        a!isNullOrEmpty(local!selectedDay),
                        local!selectedDay = fv!index
                      ),
                      "SOLID",
                      "GHOST"
                    )
                  )
                ),
                showWhen: a!isNotNullOrEmpty(local!selectedMonth)
              ),
              #"SYSTEM_SYSRULES_paragraphField"(
                label: "Grund",
                value: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/71d51822-db2b-4543-b00e-364428dbdfbc"],
                saveInto: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/71d51822-db2b-4543-b00e-364428dbdfbc"],
                required: true
              )
            }
          ),
          #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
            text: {
              "Dein Antrag wird von deinem Betreuer geprüft.",
              "Rückfragen beantwortest du über deine Aufgaben.",
              "Der Besuch wird mit deinem Gast vereinbart."
            },
            textSize: "MEDIUM",
            labelSize: "MEDIUM_PLUS"
          ),
          #"SYSTEM_SYSRULES_ButtonLayout"(
            primaryButtons: {
              #"SYSTEM_SYSRULES_buttonWidget_v1"(
                label: "Antrag Nochmal Einreichen",
                icon: "check",
                saveInto: {
                  a!save(
                    target: ri!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/1248a4bf-108e-4870-8db8-2816b7cd4bea"],
                    value: date(year(today()), local!selectedMonth, local!selectedDay)
                  )
                },
                submit: true,
                size: "LARGE",
                style: "SOLID"
              )
            },
            secondaryButtons: {
              #"SYSTEM_SYSRULES_buttonWidget_v1"(
                label: "Abbrechen",
                icon: "close",
                value: null,
                saveInto: {
                  local!selectedService,
                  local!selectedDay,
                  local!selectedMonth,
                  a!save(
                    target: ri!request,
                    value: local!initialRequest
                  )
                },
                size: "LARGE",
                color: "SECONDARY"
              )
            }
          )
        },
        style: "#333333",
        shape: "ROUNDED",
        showBorder: false
      )
    },
    backgroundColor: "#111111"
  )
)
